section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/api-gateway-patterns.json",
  "title": "API Gateway Patterns",
  "type": "object",
  "required": [
    "artefact_id",
    "gateway_id",
    "engine",
    "routes",
    "auth_strategy",
    "rate_limit_backend",
    "cors_policy",
    "observability",
    "evidence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "gateway_id": {
      "type": "string",
      "description": "ingress name (kong-prod, nginx-edge)",
      "minLength": 1
    },
    "engine": {
      "type": "string",
      "description": "kong|nginx|envoy|traefik|cloud-managed",
      "minLength": 1
    },
    "routes": {
      "type": "array",
      "description": "list of {path, upstream, timeout_ms, plugins[]} entries",
      "minItems": 1
    },
    "auth_strategy": {
      "type": "string",
      "description": "jwt|api-key|oauth-introspect|mtls",
      "minLength": 1
    },
    "rate_limit_backend": {
      "type": "string",
      "description": "redis|local-memory|cloud-managed",
      "minLength": 1
    },
    "cors_policy": {
      "type": "object",
      "description": "{allowed_origins, allowed_methods, allowed_headers, expose_headers, max_age_seconds}"
    },
    "observability": {
      "type": "object",
      "description": "{access_log_format, metrics_exporter, trace_propagation}"
    }
  },
  "additionalProperties": false
}
